        {
            TypeInfoResolver = new DefaultJsonTypeInfoResolver()
        };

        private static JsonTypeInfo<ResponseError> ResponseErrorTypeInfo =>
            (JsonTypeInfo<ResponseError>)s_options.GetTypeInfo(typeof(ResponseError));

        internal static void SerializeResponseError(Utf8JsonWriter writer, ResponseError error)
        {
            JsonSerializer.Serialize(writer, error, ResponseErrorTypeInfo);
        }

        internal static ResponseError DeserializeResponseError(string json)
        {
            return JsonSerializer.Deserialize(json, ResponseErrorTypeInfo);
        }
    }
}

